SELECT id, agent_id, session_id, role, message_type, content, tool_call_id, tool_name, tool_arguments, tool_call_status, tool_execution_time, create_time, user_id
FROM chat_history
WHERE agent_id = #{agentId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, agent_id, session_id, role, message_type, content, tool_call_id, tool_name, tool_arguments, tool_call_status, tool_execution_time, create_time, user_id
FROM chat_history
WHERE session_id = #{sessionId}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, agent_id, session_id, role, message_type, content, tool_call_id, tool_name, tool_arguments, tool_call_status, tool_execution_time, create_time, user_id
FROM chat_history
WHERE session_id = #{sessionId} and tool_call_id = #{toolCallId}
limit 1;

SELECT id, agent_id, session_id, role, message_type, content, tool_call_id, tool_name, tool_arguments, tool_call_status, tool_execution_time, create_time, user_id
FROM chat_history
WHERE user_id = #{userId}
  AND role = #{role}
  AND create_time >= #{since}
ORDER BY create_time DESC
LIMIT #{limit}

SELECT id, agent_id, session_id, role, message_type, content, tool_call_id, tool_name, tool_arguments, tool_call_status, tool_execution_time, create_time, user_id
FROM chat_history
WHERE user_id = #{userId}
  AND role = #{role}
  AND id > #{afterId}
  AND create_time >= #{since}
ORDER BY id ASC
LIMIT #{limit}

